var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"왜 혼자 있니? 친구들은?","JPN":"どうして一人でいるの？　お友達は？","ENG":"Why are you here alone? Where are your friends?","TWN":"你怎麼一個人？你的朋友們呢？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"알렉스 언니......","JPN":"アレックスお姉ちゃん……","ENG":"Alex...","TWN":"雅蕾克絲姐姐……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시가...... 절 잊어버렸어요......","JPN":"ケイシーが……私を忘れてしまったの……","ENG":"Kaci... doesn't remember me...","TWN":"卡西……忘記我了……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아르티도...... 제 말을 못 들어요.","JPN":"アルティも……私の声が聞こえないみたいで。","ENG":"Arti... can't hear me, either.","TWN":"阿爾蒂……也聽不見我說話了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"사실은...... 오늘처럼 친구랑 놀고, 같이 밥을 먹어본 건 정말 오랜만이었거든요.","JPN":"実は……今日みたいに友達と遊んで、一緒にご飯を食べたのは本当に久しぶりだったんだ。","ENG":"Actually... It's been such a long time since I played with friends and had lunch together, like I did today.","TWN":"其實……我已經很久沒有像今天這樣跟朋友一起玩，一起吃飯了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그런데 결국은 다 없던 일이 됐잖아요.","JPN":"でも結局は全部なかったことになってしまって。","ENG":"But now it's like it never happened.","TWN":"可是最後還是什麼都沒有了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면...... 차라리 처음부터 안 친해지면 좋았을 텐데......","JPN":"こうなるってわかっていたら、最初から仲良くならなければよかったのに……","ENG":"If I had known it would come to this... I wouldn't have made friends with them...","TWN":"早知道會這樣……還不如不要認識……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 넌 그 아이들을 기억하고 있잖니.","JPN":"でもあなたはあの子たちを憶えているのでしょう？","ENG":"But you still remember your friends.","TWN":"可是你記得那些朋友們不是嗎。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"매번 그랬어요. 저만 기억하고, 저만 슬퍼하고......","JPN":"毎回そうだったの。私だけ記憶して、私だけ悲しんで……","ENG":"It's always the same. Only I remember them, only I get sad...","TWN":"每次都這樣，只有我一個人記得，只有我一個人傷心……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"다른 애들이 그래요. 존재하지 않는 31번이라고.","JPN":"他の子たちに言われたの。存在しない31番だって。","ENG":"Other kids call me Student Number Thirty-one, the one who doesn't exist.","TWN":"別人都說，我是不存在的31號。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"전...... 그 애들한테 그냥 유령 같은 건가 봐요.","JPN":"私は……あの子たちにとってただの幽霊みたいなものなんだ。","ENG":"I'm... like a ghost to them.","TWN":"對她們來說……我就是幽靈般的存在。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까...... 이젠 그냥 유령으로 살래요.","JPN":"だから……もう幽霊として生きる。","ENG":"So... I'll just live like a ghost.","TWN":"所以……以後我要把自己當成幽靈。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"소원 같은 거, 어차피 이루어지지도 않을 텐데......","JPN":"願いなんか、どうせ叶わないのに……","ENG":"There is no such thing as a wish come true...","TWN":"願望之類的東西，反正也不會實現……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그렇게 하고 싶다면 말리지는 않을게.","JPN":"そうしたいなら止めやしないわ。","ENG":"If that's what you really want, I won't stop you.","TWN":"你想那麼做的話，我不會攔你。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 네가 떠나 버리면, 그 아이들도 너처럼 슬퍼하지 않으려나?","JPN":"でも、あなたが去ってしまったら、あの子たちもあなたと同じく悲しむと思わない？","ENG":"But if you leave like this, wouldn't your friends be as sad as you are?","TWN":"可是你離開的話，她們會不會也像你一樣傷心呢？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"걔들은...... 절 기억 못해요. 벌써 잊어버렸는걸요.","JPN":"あの子たちは……私を憶えていないよ。もう忘れちゃった。","ENG":"They don't remember me... I'm already forgotten.","TWN":"她們……不記得我了，已經忘記我了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 얘기할 때 귀담아 듣지 않았구나.","JPN":"フフッ。私の話をちゃんと聞いていなかったのかしら？","ENG":"Hah hah. You didn't listen to what I said.","TWN":"呵呵，看來我說的話你沒有聽進去啊。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"진짜 친구라면 잠깐 잊어버릴 수는 있어도 영원히 사라지지는 않아.","JPN":"本当の友達ならちょっとの間忘れることはあっても、永遠に記憶から消えてしまうことはないのよ。","ENG":"A true friend never goes away, even if you forget about her for a while.","TWN":"因為真正的朋友哪怕暫時忘記，也不會永遠消失。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};